INSERT INTO feedback_chips (id, name, category, explanation, positive_example, negative_example, created_at, updated_at)
VALUES
    ('009e9970-f6db-4607-b41c-a25a1b59753a', 'Color Palette', 'Visual Aesthetics', 'Assesses the impact and harmony of the color scheme. Is the palette appealing, cohesive, and fitting for the style?', 'Vibrant Color Palette (e.g., ''Colors are harmonious and engaging.'')', 'Unfitting Color Palette (e.g., ''Colors are too harsh or dull.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('077d95f7-3856-43d7-bdbf-dee40227cd1d', 'Consistency', 'Visual Aesthetics', 'Assesses the coherence of the design style across the portfolio. Is the style unified and intentional?', 'Consistent Style (e.g., ''Unified aesthetic across all projects.'')', 'Inconsistent Style (e.g., ''Style feels disjointed.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('19e415c4-37df-4cd6-876d-55ba547b78b2', 'Uniqueness', 'Personality & Originality', 'Evaluates the distinctiveness of the portfolio''s style. Does the portfolio stand out as original?', 'Unique Style (e.g., ''Portfolio feels distinctive.'')', 'Generic Style (e.g., ''Portfolio looks interchangeable.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('2335eab6-5be5-4c63-a032-77b4ff079873', 'Mobile Experience', 'Technical Execution', 'Evaluates the overall user experience on mobile devices. Is the portfolio intuitive, visually appealing, and functional on phones?', 'Strong Mobile Experience (e.g., ''Seamless and engaging on mobile.'')', 'Weak Mobile Experience (e.g., ''Cluttered or hard to use on phones.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('24f4952c-79cb-4871-8fb8-853b602d1872', 'Imagery', 'Visual Aesthetics', 'Assesses the quality and relevance of images or graphics. Are they high-quality, relevant, and visually appealing?', 'Impressive Imagery (e.g., ''Images are sharp and enhance projects.'')', 'Poor Imagery (e.g., ''Images are pixelated or irrelevant.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('30b98b51-9ddd-496b-876a-7727b2452558', 'Project Organization', 'Structure & Usability', 'Assesses the logic and clarity of project arrangement. Are projects structured in a clear, meaningful way?', 'Well-Organized Projects (e.g., ''Projects are clearly structured.'')', 'Poorly Organized Projects (e.g., ''Projects feel chaotic.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('4a49f560-9cd0-4ed1-b1d4-e0dab5147644', 'Loading Speed', 'Technical Execution', 'Assesses how quickly the portfolio loads. Is it optimized for fast performance?', 'Fast Loading Speed (e.g., ''Page loads instantly.'')', 'Slow Loading Speed (e.g., ''Images load delayed.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('501e834d-6f1f-4e1a-a944-9c1ca3297cf4', 'Storytelling', 'Concept & Process', 'Evaluates the ability to present projects narratively. Are project descriptions engaging and compelling?', 'Engaging Storytelling (e.g., ''Descriptions captivate the reader.'')', 'Weak Storytelling (e.g., ''Descriptions are dry.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('560e0fc2-b256-40f2-89a8-03b1be64d7fb', 'Clarity', 'Structure & Usability', 'Assesses the understandability of content (e.g., texts, descriptions). Are the information and messages clear?', 'Clear Content (e.g., ''Text is concise and understandable.'')', 'Unclear Content (e.g., ''Text is confusing or vague.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('646b5ca3-9478-4922-871b-c09f4cbb11e8', 'Responsiveness', 'Technical Execution', 'Evaluates the portfolio''s adaptability to different devices (e.g., desktop, tablet). Does it function well across platforms?', 'Responsive Design (e.g., ''Works seamlessly on all devices.'')', 'Poor Responsive Design (e.g., ''Issues on tablets.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('87a7cf20-40c3-499c-99b9-66c729999080', 'Font Selection', 'Visual Aesthetics', 'Evaluates the choice and suitability of fonts in the portfolio. Are they harmonious, readable, and stylistically appropriate?', 'Strong Font Selection (e.g., ''Fonts are elegant and enhance the aesthetic.'')', 'Weak Font Selection (e.g., ''Fonts feel mismatched or inconsistent.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('af2c86f7-c64d-436b-875d-30845757a5b7', 'Visual Hierarchy', 'Visual Aesthetics', 'Evaluates the arrangement and prioritization of visual elements. Does the hierarchy guide attention effectively?', 'Clear Visual Hierarchy (e.g., ''Key elements are well-prioritized.'')', 'Unclear Visual Hierarchy (e.g., ''Layout feels chaotic.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('b5cc8a19-d00c-4ae3-8158-afad2a6774b1', 'Concept Strength', 'Concept & Process', 'Assesses the originality and depth of creative ideas behind projects. Are the concepts innovative and well-developed?', 'Strong Concept (e.g., ''Innovative and thoughtful ideas.'')', 'Weak Concept (e.g., ''Ideas feel generic.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('c303eef6-f110-4836-a44d-622e60a51b62', 'Layout Design', 'Visual Aesthetics', 'Evaluates the aesthetic balance and functionality of the layout. Is the design balanced, attractive, and effective?', 'Balanced Layout Design (e.g., ''Layout is harmonious and clear.'')', 'Unbalanced Layout Design (e.g., ''Layout feels cluttered or empty.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('ca94c814-44bd-4843-a126-6ebec80cb94c', 'Navigation', 'Structure & Usability', 'Evaluates the ease of navigating the portfolio. Is it intuitive to find and explore projects?', 'Intuitive Navigation (e.g., ''Easy to find projects.'')', 'Complex Navigation (e.g., ''Confusing to navigate.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('d07be69c-734b-410f-a7a9-be7b719ac2ff', 'Personal Voice', 'Personality & Originality', 'Assesses how well the designer''s personality shines through. Is the individual voice authentic and evident?', 'Strong Personal Voice (e.g., ''Authentic and unique presence.'')', 'Weak Personal Voice (e.g., ''Feels impersonal or sterile.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('d18f3151-0e30-4154-bf72-e7f48131b6b5', 'Case Study Quality', 'Concept & Process', 'Evaluates the structure and persuasiveness of case studies (e.g., problem, solution, results). Are they detailed and convincing?', 'Strong Case Studies (e.g., ''Well-structured and persuasive.'')', 'Weak Case Studies (e.g., ''Superficial or unclear.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('d66661a4-7aca-4c81-a7f9-b05af20ad338', 'Professionalism', 'Professional Relevance', 'Evaluates the overall professionalism of the portfolio presentation. Does it appear polished and credible?', 'Professional Presentation (e.g., ''Polished and high-quality.'')', 'Unprofessional Presentation (e.g., ''Sloppy or amateurish.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('e93e3a4b-2c84-4e27-82de-6adacc130377', 'Animation Quality', 'Technical Execution', 'Evaluates the quality of animations or transitions (if present). Are they smooth and enhancing the experience?', 'Smooth Animations (e.g., ''Animations are subtle and elegant.'')', 'Clunky Animations (e.g., ''Animations feel disruptive.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'),
    ('eabba0d4-21ff-4462-ad24-e205227b7dc9', 'Problem Solving', 'Concept & Process', 'Assesses the creativity and effectiveness of solutions to design challenges. Are the approaches clever and impactful?', 'Innovative Problem Solving (e.g., ''Smart solutions to complex issues.'')', 'Inadequate Problem Solving (e.g., ''Solutions feel superficial.'')', '2025-05-16 15:25:24.063636+00', '2025-05-16 15:25:24.063636+00'); 